async function handleClaimSiblingScan(_body: Record<string, unknown>, agentId: string) {
  const db = serviceClient();

  // Fetch all sibling_scan_request_* keys that are pending
  const { data: rows, error: fetchErr } = await db
    .from("admin_config")
    .select("key, value, updated_at")
    .like("key", "sibling_scan_request_%")
    .order("updated_at", { ascending: true })
    .limit(20);

  if (fetchErr) return err(fetchErr.message, 500);

  const pendingRequests: Array<{ key: string; value: Record<string, unknown> }> = [];
  const now = Date.now();
  for (const row of rows || []) {
    const val = row.value as Record<string, unknown>;
    if (!val || val.status !== "pending") continue;

    const requestedAt = typeof val.requested_at === "string" ? Date.parse(val.requested_at) : NaN;
    const updatedAt = typeof row.updated_at === "string" ? Date.parse(row.updated_at) : NaN;
    const ageFrom = Number.isFinite(requestedAt) ? requestedAt : updatedAt;
    const isStale = !Number.isFinite(ageFrom) || now - ageFrom > SIBLING_SCAN_STALE_MS;

    if (isStale) {
      const timedOutValue = {
        ...val,
        status: "failed",
        images: [],
        error_message: "Previous folder scan timed out before the Bridge Agent returned results. Try scanning again.",
        processed_at: new Date().toISOString(),
      };
      await db
        .from("admin_config")
        .update({ value: timedOutValue, updated_at: new Date().toISOString() })
        .eq("key", row.key);
      continue;
    }

    pendingRequests.push({ key: row.key, value: val });
  }

  if (pendingRequests.length === 0) {
    return json({ ok: true, request: null });
  }

  // Claim the oldest one
  const oldest = pendingRequests[0];
  const requestId = oldest.key.replace("sibling_scan_request_", "");

