    ...oldest.value,
    status: "claimed",
    claimed_by: agentId,
    claimed_at: new Date().toISOString(),
  };

  const { error: claimErr } = await db
    .from("admin_config")
    .update({ value: claimedValue, updated_at: new Date().toISOString() })
    .eq("key", oldest.key);

